insert into jardines.salones (nombre, descripcion, descripcion_larga, capacidad, capacidad_min, capacidad_max, imagen_principal, imagenes, caracteristicas, activo, orden) values
  ('Salón de los Espejos', 'Elegante salón cubierto con iluminación regulable, climatización y acabados de lujo. Ideal para eventos íntimos y corporativos.', 'El Salón Grande es el corazón de Jardines Club Hípico, un espacio diseñado para convertir cada celebración en una experiencia memorable.  Su amplia pista de baile invita a vivir momentos llenos de energía y emoción, mientras que su escenario permite disfrutar presentaciones en vivo, música y espectáculos que hacen de cada evento algo verdaderamente especial. La distribución del salón permite crear montajes elegantes y personalizados, adaptándose perfectamente a bodas, XV años, eventos sociales o celebraciones corporativas.  La iluminación ambiental, los amplios espacios y la armonía del lugar crean una atmósfera única donde cada detalle se convierte en parte de una experiencia inolvidable.  Aquí no solo se celebra un evento… se crean recuerdos que permanecerán para siempre.', '300-400 personas', 150, 400, '/media/img/GqNFCgG.jpeg', '["/media/img/GqNFCgG.jpeg","/media/img/YVHuwPU.jpeg","/media/img/q5hBmrM.jpeg","/media/img/OoMjnAm.png","/media/img/9L0Fxvk.png","/media/img/NIB5z8l.png","/media/img/9JCYX0D.png","/media/img/WsISC1j.png","/media/img/JDexDse.mp4","/media/img/OVVYNcO.mp4","/media/img/zyLySpq.jpg","/media/img/bzohmTK.jpg","/media/img/LrtwYEZ.jpg","/media/img/oFolvxH.jpg","/media/img/5uVcOay.jpg","/media/img/dGg8Xxh.jpg","/media/img/WJxhev8.jpg","/media/img/1fcZG58.jpg","/media/img/0lK0J1F.jpg","/media/img/WPHVZ6S.jpg","/media/img/nzGjwlf.jpg","/media/img/FEOMxGn.jpg"]'::jsonb, '["Amplio salón para eventos de gran capacidad","Distribución versátil para diferentes tipos de montaje","Área especial para banquete y mesas de invitados","Espacios amplios para decoración personalizada","Escenario ideal para bandas en vivo, cantantes o presentaciones","Amplia pista de baile para animar cualquier celebración","Sistema de iluminación ambiental para ambientar el evento","Cocina equipada dentro del salón","Barra de bar para servicio de bebidas","Baños amplios y cómodos para invitados","Patio exterior para momentos al aire libre","Zona especial para sesiones fotográficas","Área recreativa infantil con alberca de pelotas","Espacios decorativos para eventos temáticos","Ambiente elegante ideal para celebraciones memorables"]'::jsonb, true, 1),
  ('Salón Encanto', 'Espacio amplio con decoración cálida y romántica, perfecto para bodas, XV años y celebraciones familiares llenas de magia.', 'El Salón Encanto es un espacio amplio y versátil diseñado para transformar cualquier celebración en una experiencia memorable. Su elegante estructura techada permite disfrutar del evento con total comodidad mientras se mantiene la conexión con los jardines y el entorno natural.  Gracias a su gran capacidad y distribución flexible, este salón es ideal para bodas, XV años, fiestas temáticas, eventos familiares y celebraciones corporativas. Cuenta con áreas perfectamente adaptables para montajes elegantes, pista de baile, escenarios musicales y zonas lounge que elevan la experiencia de cada evento.  De día, la luz natural y la vista hacia los jardines crean una atmósfera fresca y acogedora. Por la noche, la iluminación ambiental y la pista de baile iluminada convierten el espacio en un escenario vibrante perfecto para celebrar, bailar y disfrutar.  El Salón Encanto es el equilibrio perfecto entre amplitud, estilo y versatilidad, permitiendo crear eventos únicos que tus invitados recordarán por mucho tiempo.', '200-300 personas', 200, 300, '/media/img/GsY3zXF.png', '["/media/img/GsY3zXF.png","/media/img/Jg9SrhI.jpeg","/media/img/oJFrsLZ.jpeg","/media/img/HmcAg2Z.jpeg","/media/img/bGnm9yN.jpeg","/media/img/lQccU4q.jpeg","/media/img/ERMx9k1.jpeg","/media/img/4PURIMU.jpeg","/media/img/Pc1vzXZ.jpeg","/media/img/T4Iu00h.jpeg","/media/img/Q0NrnQW.jpeg","/media/img/25Aeqfh.mp4","/media/img/ZJC0JRv.mp4","/media/img/aRdlLip.mp4","/media/img/DPHY5YQ.jpg","/media/img/VsTX2Es.mp4","/media/img/lS2Xe4T.mp4","/media/img/8nSzGlh.jpg","/media/img/VD8c9lm.jpg","/media/img/w4Nwc7u.jpg","/media/img/ZkvrSIS.jpg","/media/img/IsnszTR.jpg"]'::jsonb, '["Amplio salón techado para eventos sociales","Área para DJ o música en vivo","Montajes flexibles para diferentes estilos de evento","Pista de baile iluminada para ambientación nocturna","Ambiente elegante y versátil","Ideal para decoraciones temáticas o tradicionales","Iluminación ambiental para eventos nocturnos"]'::jsonb, true, 2),
  ('Espacio Nocturno (Eclipse)', 'Espacio moderno tipo Night Club con iluminación LED, pista de baile, proyector con pantalla gigante y ambiente exclusivo. Ideal para cumpleaños, after parties, eventos juveniles y celebraciones nocturnas llenas de energía.', 'Nuestro Espacio Nocturno es un espacio diseñado para eventos nocturnos que buscan un ambiente moderno, dinámico y lleno de energía. Cuenta con una amplia pista de baile, iluminación ambiental tipo antro y un sistema de proyección con pantalla gigante que transforma cualquier celebración en una experiencia inolvidable.  El espacio incluye área lounge con mesas y sillones para convivir cómodamente, además de un servicio de bebidas que complementa perfectamente el ambiente de fiesta. Su iluminación LED y diseño contemporáneo permiten crear diferentes atmósferas según el tipo de evento, desde celebraciones juveniles hasta reuniones privadas con estilo.  Es el lugar ideal para cumpleaños, graduaciones, after parties, reuniones con amigos o eventos temáticos, ofreciendo una experiencia única que combina música, luces y entretenimiento en un solo espacio.', '80-120 personas', 50, 120, '/media/img/F6GeNNq.png', '["/media/img/F6GeNNq.png","/media/img/S502f1o.jpeg","/media/img/NO050nK.jpeg","/media/img/To7QUrH.jpeg","/media/img/vhEY60N.jpeg","/media/img/yYflRNX.jpeg","/media/img/IxvKC6G.jpeg","/media/img/cfkt9vB.jpeg","/media/img/fW3YRjj.jpeg","/media/img/MGOqIQU.mp4","/media/img/7dPLEbq.mp4"]'::jsonb, '["Cabina de DJ para ambientación musical","Sistema de sonido para música y presentaciones","Amplia pista de baile","Proyector con pantalla gigante","Iluminación LED tipo antro","Ambientación nocturna personalizable","Área lounge con mesas y sillones","Espacios para convivir y descansar","Distribución ideal para eventos sociales","Servicio de bebidas","Área para DJ o animación musical","Espacios para decoración temática"]'::jsonb, true, 3),
  ('Jardines', 'Hermosos jardines naturales rodeados de vegetación exuberante. El escenario perfecto para ceremonias y festejos al aire libre.', 'Los Jardines de Jardines Club Hípico son el alma del lugar y el espacio que da vida a su nombre. Un entorno natural cuidadosamente mantenido que ofrece amplias áreas verdes, vistas abiertas y una atmósfera fresca y elegante para celebraciones únicas.  Sus extensas áreas permiten montar desde eventos íntimos hasta celebraciones de gran escala, adaptándose perfectamente a bodas, XV años, fiestas sociales, ceremonias al aire libre o eventos corporativos. La amplitud del terreno brinda libertad para crear montajes espectaculares con carpas, pistas de baile, escenarios, zonas lounge o áreas gastronómicas.  Rodeados de naturaleza, con paisajes abiertos y jardines impecablemente cuidados, este espacio ofrece el escenario perfecto para eventos que buscan algo más que un salón tradicional: una experiencia elegante al aire libre.  Cada celebración aquí se transforma en un momento especial donde la naturaleza, la elegancia y la amplitud se unen para crear recuerdos inolvidables.', '400-600 personas', null, null, '/media/img/cQFcFEC.jpeg', '["/media/img/fP9Bhew.png","/media/img/s27TD11.jpeg","/media/img/1qM0786.jpeg","/media/img/NRFjbiX.jpeg","/media/img/RYrYJQn.jpeg","/media/img/cQFcFEC.jpeg","/media/img/VvxlY2I.jpeg","/media/img/KjByJEu.jpeg","/media/img/WgZwUNN.jpeg","/media/img/eDTtUTe.jpeg","/media/img/NRFjbiX.jpeg","/media/img/7B2TkTL.jpeg","/media/img/VPgqZZK.mp4","/media/img/yHdczws.jpg","/media/img/1RYGMz9.jpg","/media/img/xpXwKY6.jpg","/media/img/9LzLa95.jpg","/media/img/6a7ILRt.jpg","/media/img/wQdM8cI.jpg","/media/img/jytOkQL.jpg","/media/img/XloOMkI.jpg","/media/img/ww16bh0.jpg","/media/img/omBNQRh.jpg","/media/img/RulgWiR.jpg","/media/img/iCJTgJs.jpg","/media/img/2vrHFCs.jpg","/media/img/hYvc3Wz.jpg","/media/img/0btSqnb.mp4"]'::jsonb, '["Amplias áreas verdes para eventos al aire libre","Espacio ideal para montajes con carpas y estructuras temporales","Escenario natural para ceremonias, recepciones y sesiones fotográficas","Jardines cuidadosamente mantenidos y visualmente atractivos","Gran capacidad para eventos sociales y celebraciones de gran formato","Áreas versátiles para pistas de baile, zonas lounge y montajes personalizados","Ideal para bodas, XV años, fiestas temáticas y eventos empresariales","Vistas amplias que realzan la experiencia del evento","Espacio perfecto para celebraciones elegantes en contacto con la naturaleza"]'::jsonb, true, 4),
  ('Área Infantil Pony', 'Espacio infantil al aire libre con amplio patio y variedad de juegos para que los niños disfruten al máximo. Ideal para fiestas infantiles, cumpleaños y celebraciones familiares en un ambiente seguro y divertido.', 'El área Pony y Juegos está especialmente diseñada para eventos infantiles, ofreciendo un espacio amplio al aire libre donde los niños pueden jugar, explorar y divertirse con total libertad.  Cuenta con una variedad de juegos recreativos, trampolines y estructuras infantiles pensadas para mantener a los pequeños entretenidos durante toda la celebración. Su amplio patio permite realizar actividades, dinámicas y juegos al aire libre, creando una experiencia llena de diversión para todos los invitados.  Además, el área puede complementarse con la renta de juegos adicionales y diferentes amenidades para personalizar cada fiesta según el tipo de evento.  Este espacio es ideal para fiestas infantiles, cumpleaños, reuniones familiares y celebraciones para niños, brindando un ambiente seguro, dinámico y lleno de alegría.', '100-150 personas', 100, 150, '/media/img/bjVFkHI.jpeg', '["/media/img/eH93AJ1.jpeg","/media/img/bjVFkHI.jpeg","/media/img/4uJQ7l7.jpeg","/media/img/vi4MCX4.jpeg","/media/img/YibFy63.jpeg","/media/img/nzIZ9BM.jpeg","/media/img/aud3Xas.jpeg","/media/img/3MqwugS.mp4","/media/img/BVBfEFU.jpg"]'::jsonb, '["Variedad de juegos recreativos","Trampolines para niños","Resbaladillas y estructuras de juego","Amplio patio al aire libre","Zona pensada para actividades infantiles","Área segura para niños","Espacio adaptable para fiestas infantiles"]'::jsonb, true, 5),
  ('Capilla', 'Elegante capilla para ceremonias y misas, ideal para bodas, XV años, bautizos y eventos especiales. Puede contratarse como complemento de cualquier salón o rentarse de forma independiente para ceremonias íntimas.', 'Nuestra Capilla para Ceremonias es un espacio elegante y especial diseñado para realizar misas y ceremonias dentro del mismo recinto del evento, brindando comodidad y una experiencia completa para los invitados.  El espacio cuenta con una estructura amplia y luminosa que permite crear una atmósfera solemne y hermosa para momentos únicos como bodas, XV años, bautizos y ceremonias religiosas. Su diseño permite una decoración personalizada para adaptarse a cada tipo de celebración.  La capilla puede contratarse como complemento de cualquiera de nuestros salones, permitiendo realizar la ceremonia y la recepción en el mismo lugar, o también puede rentarse de forma independiente para ceremonias privadas.  Es el espacio perfecto para quienes desean celebrar un momento especial en un ambiente elegante, cómodo y memorable.', '50-150 personas', 50, 150, '/media/img/9NiMw7K.png', '["/media/img/UYE0gAg.png","/media/img/sBkiENk.png","/media/img/9NiMw7K.png","/media/img/7tJFLcg.jpg","/media/img/FuTMIip.jpg","/media/img/AD6P4xz.jpg","/media/img/ignnXxZ.jpg"]'::jsonb, '["Área diseñada para ceremonias religiosas","Ideal para bodas, XV años, bautizos y misas","Espacio amplio y luminoso","Área adaptable para decoración ceremonial","Escenario principal para altar o ceremonia","Puede contratarse como extra con cualquier salón","Disponible para renta independiente","Ideal para ceremonias íntimas o grandes celebraciones"]'::jsonb, true, 6),
  ('Quiosco', 'Un espacio íntimo rodeado de áreas verdes, ideal para reuniones privadas y celebraciones pequeñas. Su terraza techada, jardín propio y ambiente tranquilo crean el escenario perfecto para convivencias familiares, comidas especiales o eventos íntimos en contacto con la naturaleza.', 'El Quiosco Jardín es un espacio encantador diseñado para quienes buscan celebrar en un ambiente más íntimo y relajado dentro de Jardines Club Hípico. Su terraza techada ofrece un lugar cómodo y protegido para convivir, mientras que su jardín privado crea un entorno natural perfecto para reuniones familiares, cumpleaños, comidas especiales o pequeños eventos sociales.  Este espacio combina naturaleza, tranquilidad y comodidad. Cuenta con una hermosa vista hacia los jardines, una fuente decorativa que aporta un ambiente agradable y una parrilla ideal para reuniones tipo parrillada o convivencias informales. Su patio privado permite disfrutar del aire libre en un ambiente exclusivo y acogedor.  El Quiosco Jardín es ideal para quienes desean un evento más cercano y personalizado, rodeado de naturaleza y con la privacidad perfecta para compartir momentos especiales con familiares y amigos.', '30-50 personas', 30, 50, '/media/img/kgI3kqI.jpg', '["/media/img/sxREpy5.jpg","/media/img/r6YLYRn.jpg","/media/img/6jxmKPw.jpg","/media/img/4bbMZTM.jpg","/media/img/dsmebc3.jpg","/media/img/QcEIFgG.jpg","/media/img/AjEgkJ7.jpg","/media/img/iHZ01Cu.jpg"]'::jsonb, '["Terraza techada tipo quiosco","Jardín privado","Parrilla para convivencias","Fuente decorativa","Patio exclusivo","Vista panorámica a los jardines","Ambiente íntimo y familiar","Ideal para eventos pequeños y reuniones privadas","Espacio perfecto para comidas familiares o celebraciones especiales"]'::jsonb, true, 7),
  ('Estancias (Bungalos)', 'Espacios cómodos diseñados para descansar dentro de Jardines Club Hípico. Ideales para quienes desean hospedarse después de su evento o simplemente disfrutar una estancia tranquila rodeados de naturaleza.', 'Los Búngalos de Jardines Club Hípico ofrecen una opción cómoda y práctica para quienes desean descansar dentro del mismo lugar del evento. Rodeados de áreas verdes y ubicados cerca de nuestras instalaciones principales, permiten a los invitados disfrutar de una estancia tranquila sin necesidad de trasladarse después de la celebración. Estos espacios están diseñados para brindar comodidad y descanso, contando con habitaciones amuebladas, camas confortables y baño privado. Son ideales tanto para quienes desean pasar la noche después de un evento como para quienes buscan una estancia relajada durante el día dentro del complejo. Dentro de los búngalos existen dos tipos de estancias: algunos funcionan como pequeños espacios tipo suite con sala, balcón y baño completo, mientras que otros son habitaciones amplias con múltiples literas, ideales para grupos grandes de invitados. Gracias a su ubicación cercana a los jardines y al área del quiosco, los búngalos permiten combinar celebración y descanso en un mismo lugar, ofreciendo una experiencia más cómoda para anfitriones e invitados.', null, null, null, '/media/img/WvvLXxr.jpg', '["/media/img/sGw9POY.jpg","/media/img/F7NNzpw.jpg","/media/img/l05HUuf.jpg","/media/img/5xzyMKr.jpg","/media/img/As9nG6N.jpg","/media/img/UsftLAV.jpg","/media/img/h560hVl.jpg","/media/img/zj9flET.jpg","/media/img/aR3tN4q.jpg","/media/img/WR4Ggao.jpg"]'::jsonb, '["Habitaciones cómodas y amuebladas","Camas confortables","Baño privado","Regadera","Ubicación dentro del complejo Jardines Club Hípico","Ideal para hospedaje después de eventos","Ambiente tranquilo rodeado de naturaleza"]'::jsonb, true, 8);
